{
    "health_coverage": {
        "Physical Health": {
            "Plan": "LifeFirst Standard Plan",
            "Cost": "€100/month",
            "Coverage": "Comprehensive physical health with 24/7 support, low 5% deductible, telemedicine, gym reimbursement",
            "Limits": "Covers all medically necessary treatments, specialist visits, hospitalization, preventive care",
            "Exclusions": "Cosmetic surgery (non-medical), experimental treatments not approved in Germany"
        },
        "Mental Health": {
            "Plan": "HealthFirst Standard Plan",
            "Cost": "€60/month",
            "Coverage": "Integrated mental health care coordination, therapy sessions, psychiatric care",
            "Limits": "Up to €10,000/year for therapy; unlimited crisis intervention",
            "Exclusions": "Non-licensed therapy providers, alternative treatments outside recognized mental health scope"
        }
    },
    "property_coverage": {
        "Plan": "InsurePlus Standard Coverage",
        "Cost": "€60/month",
        "Coverage": "Comprehensive protection for home contents and professional photography equipment",
        "Limits": "Electronics up to €3,000, photography equipment integrated up to €15,000, temporary accommodation if home is uninhabitable",
        "Exclusions": "Wear and tear, intentional damage, items without proof of ownership"
    },
    "travel_coverage": {
        "Plan": "VitalPlus European Plan",
        "Cost": "€55/month",
        "Coverage": "All EU/EEA + Switzerland + UK travel, adventure activities, professional on-location photography, eco-tourism/wellness travel",
        "Photography Equipment Coverage": "Up to €10,000 in Europe, expedited claims for professionals",
        "Professional Liability": "€1,000,000 for professional incidents in Europe",
        "Exclusions": "No coverage outside Europe — separate short-term policies required for Iceland and Bali. Extreme sports outside listed adventure activities excluded"
    },
    "additional_services": {},
    "total_budget": {
        "Monthly Cost": "€275",
        "Annual Cost": "€3,300"
    }
}
